// Snapshot channel context and compute yesterday date window
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const since = Math.floor(new Date(yesterday.toISOString().split('T')[0] + 'T00:00:00Z').getTime() / 1000);
const until = Math.floor(new Date(yesterday.toISOString().split('T')[0] + 'T23:59:59Z').getTime() / 1000);

return $input.all().map(item => ({
  json: {
    channel_id:   item.json.channel_id,
    account_id:   item.json.account_id,
    access_token: item.json.access_token,
    platform:     'instagram',
    metric_date:  yesterday.toISOString().split('T')[0],
    since,
    until
  }
}));

const apiItems = $input.all();
const channelItems = $('Init - Channel State').all();

return apiItems.map((apiItem, idx) => {
  const channel = channelItems[idx]?.json || {};
  const data = apiItem.json.data || [];

  let reach = 0, impressions = 0, engagement = 0, profileViews = 0, followerCount = 0;

  data.forEach(metric => {
    const val = metric.values?.[0]?.value || 0;
    if (metric.name === 'reach')              reach = val;
    if (metric.name === 'impressions')        impressions = val;
    if (metric.name === 'total_interactions') engagement = val;
    if (metric.name === 'profile_views')      profileViews = val;
    if (metric.name === 'follower_count')     followerCount = val;
  });

  return {
    json: {
      channel_id:         channel.channel_id,
      platform:           'instagram',
      metric_date:        channel.metric_date,
      reach:              parseInt(reach),
      impressions:        parseInt(impressions),
      engagements:        parseInt(engagement),
      clicks:             0,
      likes:              0,
      comments:           0,
      shares:             0,
      saves:              0,
      video_views:        0,
      watch_time_seconds: 0,
      profile_visits:     parseInt(profileViews),
      follower_count:     parseInt(followerCount),
      created_at:         new Date().toISOString()
    }
  };
});
